// Execution Validation Logic
const results = {
  timestamp: new Date().toISOString(),
  workflow_id: $workflow.id,
  execution_id: $execution.id,
  status: 'success',
  validated_nodes: [],
  errors: [],
  performance_metrics: {
    total_execution_time: 0,
    node_execution_times: {},
    memory_usage: process.memoryUsage(),
    cpu_usage: process.cpuUsage()
  }
};

// Validate each node execution
const nodes_to_validate = [
  'GitHub Integration',
  'Google Docs Integration', 
  'Email Notification',
  'VPN Switch Node',
  'Local AI Node (Gemma 3n/SHAKTI)',
  'Test Command Node'
];

for (const node_name of nodes_to_validate) {
  try {
    const node_data = $node[node_name];
    if (node_data && node_data.json) {
      results.validated_nodes.push({
        node: node_name,
        status: 'success',
        data_size: JSON.stringify(node_data.json).length,
        execution_time: node_data.executionTime || 0
      });
    } else {
      results.errors.push({
        node: node_name,
        error: 'No data returned or node failed'
      });
    }
  } catch (error) {
    results.errors.push({
      node: node_name,
      error: error.message
    });
  }
}

// Calculate overall status
if (results.errors.length > 0) {
  results.status = 'partial_success';
  if (results.errors.length >= nodes_to_validate.length / 2) {
    results.status = 'failed';
  }
}

// Performance calculations
results.performance_metrics.total_execution_time = 
  results.validated_nodes.reduce((total, node) => total + (node.execution_time || 0), 0);

results.performance_metrics.success_rate = 
  (results.validated_nodes.length / nodes_to_validate.length) * 100;

results.performance_metrics.error_rate = 
  (results.errors.length / nodes_to_validate.length) * 100;

// Add Hindi status message
if (results.status === 'success') {
  results.hindi_message = 'सभी nodes सफलतापूर्वक execute हुए हैं!';
} else if (results.status === 'partial_success') {
  results.hindi_message = 'कुछ nodes में समस्या है, लेकिन workflow चालू है।';
} else {
  results.hindi_message = 'Workflow execution में गंभीर समस्या है।';
}

return results;

