    environment: process.env.NODE_ENV || 'production'
  },

  node_results: {
    vpn_switch: {
      status: $node['VPN Switch Node'].json ? 'success' : 'failed',
      country: $node['Webhook Trigger'].json['vpn_country'] || 'IN',
      execution_time: $node['VPN Switch Node'].executionTime || 0
