  next_steps: []
};

// Calculate performance metrics
let successful_count = 0;
let total_time = 0;
let node_times = [];

Object.keys(workflow_summary.node_results).forEach(node_key => {
  const node_result = workflow_summary.node_results[node_key];
  if (node_result.status === 'success') {
    successful_count++;
  }
  if (node_result.execution_time) {
    total_time += node_result.execution_time;
    node_times.push({name: node_key, time: node_result.execution_time});
  }
});

workflow_summary.performance_metrics.success_rate = (successful_count / Object.keys(workflow_summary.node_results).length) * 100;
workflow_summary.performance_metrics.average_node_time = total_time / Object.keys(workflow_summary.node_results).length;
workflow_summary.performance_metrics.error_count = Object.keys(workflow_summary.node_results).length - successful_count;

workflow_summary.summary_statistics.successful_nodes = successful_count;
workflow_summary.summary_statistics.failed_nodes = Object.keys(workflow_summary.node_results).length - successful_count;
workflow_summary.summary_statistics.processing_time.total_time = total_time;

if (node_times.length > 0) {
  node_times.sort((a, b) => a.time - b.time);
  workflow_summary.summary_statistics.processing_time.fastest_node = node_times[0].name;
  workflow_summary.summary_statistics.processing_time.slowest_node = node_times[node_times.length - 1].name;
}

