} else if (workflow_summary.performance_metrics.success_rate >= 70) {
  workflow_summary.hindi_summary = `⚠️ आपका workflow ${workflow_summary.performance_metrics.success_rate.toFixed(1)}% success rate के साथ चला है। कुछ components में minor issues हैं लेकिन overall functionality ठीक है। कृपया failed nodes को check करें।`;
